DROP TABLE IF EXISTS `ibl_olympics_box_scores`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `ibl_olympics_box_scores` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `game_date` date NOT NULL COMMENT 'Game date',
  `name` varchar(16) DEFAULT '' COMMENT 'Player name',
  `pos` enum('PG','SG','SF','PF','C','G','F','GF','') DEFAULT '' COMMENT 'Position played',
  `pid` int(11) DEFAULT NULL COMMENT 'Player ID (references ibl_plr)',
  `visitor_teamid` int(11) DEFAULT NULL COMMENT 'Visiting team ID (FK to ibl_olympics_team_info)',
  `home_teamid` int(11) DEFAULT NULL COMMENT 'Home team ID (FK to ibl_olympics_team_info)',
  `game_of_that_day` int(11) DEFAULT NULL COMMENT 'Game number for that date',
  `attendance` int(11) DEFAULT NULL COMMENT 'Game attendance',
  `capacity` int(11) DEFAULT NULL COMMENT 'Arena capacity',
  `visitor_wins` int(11) DEFAULT NULL COMMENT 'Visitor team wins before game',
  `visitor_losses` int(11) DEFAULT NULL COMMENT 'Visitor team losses before game',
  `home_wins` int(11) DEFAULT NULL COMMENT 'Home team wins before game',
  `home_losses` int(11) DEFAULT NULL COMMENT 'Home team losses before game',
  `teamid` int(11) DEFAULT NULL COMMENT 'Player''s team ID (visitor or home)',
  `game_min` tinyint(3) unsigned DEFAULT NULL COMMENT 'Minutes played',
  `game_2gm` tinyint(3) unsigned DEFAULT NULL COMMENT 'Field goals made',
  `game_2ga` tinyint(3) unsigned DEFAULT NULL COMMENT 'Field goals attempted',
  `game_ftm` tinyint(3) unsigned DEFAULT NULL COMMENT 'Free throws made',
  `game_fta` tinyint(3) unsigned DEFAULT NULL COMMENT 'Free throws attempted',
  `game_3gm` tinyint(3) unsigned DEFAULT NULL COMMENT 'Three pointers made',
  `game_3ga` tinyint(3) unsigned DEFAULT NULL COMMENT 'Three pointers attempted',
  `game_orb` tinyint(3) unsigned DEFAULT NULL COMMENT 'Offensive rebounds',
  `game_drb` tinyint(3) unsigned DEFAULT NULL COMMENT 'Defensive rebounds',
  `game_ast` tinyint(3) unsigned DEFAULT NULL COMMENT 'Assists',
  `game_stl` tinyint(3) unsigned DEFAULT NULL COMMENT 'Steals',
  `game_tov` tinyint(3) unsigned DEFAULT NULL COMMENT 'Turnovers',
  `game_blk` tinyint(3) unsigned DEFAULT NULL COMMENT 'Blocks',
  `game_pf` tinyint(3) unsigned DEFAULT NULL COMMENT 'Personal fouls',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `uuid` char(36) NOT NULL DEFAULT uuid() COMMENT 'Public API identifier',
  `game_type` tinyint(3) unsigned GENERATED ALWAYS AS (case when month(`game_date`) = 6 then 2 when month(`game_date`) = 10 then 3 when month(`game_date`) = 0 then 0 else 1 end) STORED,
  `season_year` smallint(5) unsigned GENERATED ALWAYS AS (case when year(`game_date`) = 0 then 0 when month(`game_date`) >= 10 then year(`game_date`) + 1 else year(`game_date`) end) STORED,
  `calc_points` smallint(5) unsigned GENERATED ALWAYS AS (`game_2gm` * 2 + `game_ftm` + `game_3gm` * 3) STORED,
  `calc_rebounds` tinyint(3) unsigned GENERATED ALWAYS AS (`game_orb` + `game_drb`) STORED,
  `calc_fg_made` tinyint(3) unsigned GENERATED ALWAYS AS (`game_2gm` + `game_3gm`) STORED,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uuid` (`uuid`),
  UNIQUE KEY `uq_game_player` (`game_date`,`pid`,`visitor_teamid`,`home_teamid`,`game_of_that_day`,`teamid`),
  KEY `idx_date` (`game_date`),
  KEY `idx_pid` (`pid`),
  KEY `idx_visitor_tid` (`visitor_teamid`),
  KEY `idx_home_tid` (`home_teamid`),
  KEY `idx_date_pid` (`game_date`,`pid`),
  KEY `idx_date_home_visitor` (`game_date`,`home_teamid`,`visitor_teamid`),
  KEY `idx_team_id` (`teamid`),
  KEY `idx_gt_points` (`game_type`,`calc_points`),
  KEY `idx_gt_rebounds` (`game_type`,`calc_rebounds`),
  KEY `idx_gt_fg_made` (`game_type`,`calc_fg_made`),
  KEY `idx_gt_ast` (`game_type`,`game_ast`),
  KEY `idx_gt_stl` (`game_type`,`game_stl`),
  KEY `idx_gt_blk` (`game_type`,`game_blk`),
  KEY `idx_gt_tov` (`game_type`,`game_tov`),
  KEY `idx_gt_ftm` (`game_type`,`game_ftm`),
  KEY `idx_gt_3gm` (`game_type`,`game_3gm`),
  KEY `idx_gt_pid` (`game_type`,`pid`),
  KEY `idx_gt_pid_season` (`game_type`,`pid`,`season_year`),
  CONSTRAINT `fk_olympics_boxscore_home` FOREIGN KEY (`home_teamid`) REFERENCES `ibl_olympics_team_info` (`teamid`) ON UPDATE CASCADE,
  CONSTRAINT `fk_olympics_boxscore_player` FOREIGN KEY (`pid`) REFERENCES `ibl_plr` (`pid`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_olympics_boxscore_team` FOREIGN KEY (`teamid`) REFERENCES `ibl_olympics_team_info` (`teamid`) ON UPDATE CASCADE,
  CONSTRAINT `fk_olympics_boxscore_visitor` FOREIGN KEY (`visitor_teamid`) REFERENCES `ibl_olympics_team_info` (`teamid`) ON UPDATE CASCADE,
  CONSTRAINT `chk_olympics_box_minutes` CHECK (`game_min` is null or `game_min` >= 0 and `game_min` <= 70)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Individual player statistics for Olympics games';
/*!40101 SET character_set_client = @saved_cs_client */;
